INSERT INTO volumes (characters, concepts, count_of_issues, description, id, name, start_year, first_issue.id, image.screen_url, publisher.id) VALUES ('[{"id": 9274}, {"id": 7859}, {"id": 9275}, {"id": 9276}, {"id": 1900}, {"id": 9279}, {"id": 34368}, {"id": 33171}, {"id": 68741}, {"id": 179055}, {"id": 68742}, {"id": 68743}, {"id": 68744}, {"id": 68745}, {"id": 150675}, {"id": 178644}, {"id": 179045}, {"id": 179046}, {"id": 179047}, {"id": 179053}, {"id": 179054}, {"id": 66567}, {"id": 66566}, {"id": 49893}, {"id": 40239}, {"id": 39780}, {"id": 22892}, {"id": 21464}, {"id": 21451}, {"id": 9878}, {"id": 9283}, {"id": 9282}, {"id": 9280}, {"id": 9278}, {"id": 9277}]', '[{"id": 57252}]', '28', '<p>Running for twenty-eight issues from 1938-1942, Single Series was a series of color newspaper reprints featuring various comic strips. Although most of the issues focused on a different character, several issues featured the same character:</p><ul><li><a href="/abbie/4005-9275/" data-ref-id="4005-9275">Abbie</a> an'' <a href="/slats/4005-9276/" data-ref-id="4005-9276">Slats</a>: 25, 28*</li><li><a href="/broncho-bill/4005-34368/" data-ref-id="4005-34368">Broncho Bill</a>: 2, 19</li><li><a href="/ella-cinders/4005-9274/" data-ref-id="4005-9274">Ella Cinders</a>: 3, 21, 28*</li><li><a href="/jim-hardy/4005-7859/" data-ref-id="4005-7859">Jim Hardy</a>: 6, 27</li><li><a href="/lil-abner/4005-9279/" data-ref-id="4005-9279">Li''l Abner</a>: 4, 18 </li><li><a href="/little-mary-mixup/4005-33171/" data-ref-id="4005-33171">Little Mary Mixup</a>: 10, 26</li></ul><p>*Ella Cinders and Abbie an'' Slats were both in the same issue, the only issue to combine two character groups, as well as the final issue.</p>', '766', 'Single Series', '1938', '164287', 'https://comicvine.gamespot.com/a/uploads/screen_medium/0/9116/880845-1.jpg', '5');
INSERT INTO volumes (characters, concepts, count_of_issues, description, id, name, start_year, first_issue.id, image.screen_url, publisher.id) VALUES ('[{"id": 31442}, {"id": 75456}, {"id": 75454}, {"id": 75457}, {"id": 14352}, {"id": 28557}, {"id": 14361}, {"id": 14366}, {"id": 14353}, {"id": 12107}, {"id": 14364}, {"id": 14363}, {"id": 76091}, {"id": 9541}, {"id": 14359}, {"id": 65435}, {"id": 9537}, {"id": 7849}, {"id": 14354}, {"id": 14360}, {"id": 2856}, {"id": 14351}, {"id": 4014}, {"id": 9377}, {"id": 68891}, {"id": 75455}, {"id": 2686}, {"id": 2694}, {"id": 3854}, {"id": 7279}, {"id": 19824}, {"id": 67769}, {"id": 68886}, {"id": 2683}, {"id": 2847}, {"id": 3049}, {"id": 3851}, {"id": 3864}, {"id": 3974}, {"id": 3977}, {"id": 4000}, {"id": 4024}, {"id": 5482}, {"id": 5635}, {"id": 6071}, {"id": 6077}, {"id": 6079}, {"id": 8055}, {"id": 9671}, {"id": 9672}, {"id": 10619}, {"id": 10691}, {"id": 10735}, {"id": 11119}, {"id": 11766}, {"id": 11784}, {"id": 12094}, {"id": 12142}, {"id": 12990}, {"id": 14335}, {"id": 14336}, {"id": 14338}, {"id": 15799}, {"id": 16648}, {"id": 16776}, {"id": 17406}, {"id": 17417}, {"id": 19192}, {"id": 19712}, {"id": 19792}, {"id": 20678}, {"id": 20976}, {"id": 21063}, {"id": 21072}, {"id": 22677}, {"id": 22694}, {"id": 22925}, {"id": 23881}, {"id": 24580}, {"id": 24902}, {"id": 27537}, {"id": 31251}, {"id": 31333}, {"id": 33141}, {"id": 34064}, {"id": 34422}, {"id": 34423}, {"id": 35567}, {"id": 35568}, {"id": 36673}, {"id": 36674}, {"id": 37303}, {"id": 37554}, {"id": 38446}, {"id": 38634}, {"id": 38912}, {"id": 39019}, {"id": 39610}, {"id": 39871}, {"id": 39874}, {"id": 40051}, {"id": 44016}, {"id": 44057}, {"id": 51231}, {"id": 52310}, {"id": 53218}, {"id": 53397}, {"id": 58664}, {"id": 62768}, {"id": 62974}, {"id": 63206}, {"id": 65452}, {"id": 65456}, {"id": 67267}, {"id": 67377}, {"id": 68888}, {"id": 70043}, {"id": 74883}, {"id": 74949}, {"id": 87919}, {"id": 96054}, {"id": 114360}]', 'NaN', '167', '<p>Jumbo Comics was a comic book anthology that lasted for 167 issues from 1938-1953, the series is probably best known for featuring <a href="/sheena/4005-31442/" data-ref-id="4005-31442">Sheena, Queen of the Jungle</a> -the first female to get her own comic book- during the bulk of its run with only a few issues at the beginning and end of the series where she was not the story featured on the cover.</p><h4>Reprints (single issues)</h4><ul><li><a href="/jumbo-comics/4050-113122/" data-ref-id="4050-113122">Jumbo Comics</a> (#1-8, 10-30)</li></ul><h4>Collected Editions</h4><ul><li><a href="https://comicvine.gamespot.com/gwandanaland-comics-12211483-the-complete-sky-girl/4000-682316/">The Complete Sky Girl: Volumes 1 &amp; 2</a> (Sky Girl stories from #68-129)</li><li><a href="https://comicvine.gamespot.com/gwandanaland-comics-700-jumbo-comics-volume-1/4000-681284/">Jumbo Comics Volume 1</a> (#1-6)</li><li><a href="https://comicvine.gamespot.com/gwandanaland-comics-701-jumbo-comics-volume-2/4000-681285/">Jumbo Comics Volume 2</a> (#7-12)</li><li><a href="https://comicvine.gamespot.com/gwandanaland-comics-702-jumbo-comics-volume-3/4000-681286/">Jumbo Comics: Volume 3</a> (#13-18)</li><li><a href="https://comicvine.gamespot.com/gwandanaland-comics-703-jumbo-comics-volume-4/4000-681287/">Jumbo Comics: Volume 4</a> (#19-24)</li><li><a href="https://comicvine.gamespot.com/gwandanaland-comics-704-jumbo-comics-volume-5/4000-681288/">Jumbo Comics: Volume 5</a> (#25-30)</li></ul>', '769', 'Jumbo Comics', '1938', '123500', 'https://comicvine.gamespot.com/a/uploads/screen_medium/0/9116/1556940-38491.jpg', '8');
INSERT INTO volumes (characters, concepts, count_of_issues, description, id, name, start_year, first_issue.id, image.screen_url, publisher.id) VALUES ('[{"id": 2957}, {"id": 21570}, {"id": 65430}, {"id": 63628}, {"id": 63627}, {"id": 39984}, {"id": 39099}, {"id": 38840}, {"id": 36190}, {"id": 28545}, {"id": 1376}, {"id": 20177}, {"id": 20169}, {"id": 12588}, {"id": 10756}, {"id": 6640}, {"id": 3061}, {"id": 1510}]', 'NaN', '6', '<p>Movie Comics was a six-issue anthology series published in 1939 that combined traditional comic stories alongside stories created by using movie stills for the artwork.</p>', '771', 'Movie Comics', '1939', '92469', 'https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/59474-771-92469-1-movie-comics.jpg', '10');
