}, {"id": 37531}, {"id": 37532}, {"id": 37533}, {"id": 37590}, {"id": 37591}, {"id": 37592}, {"id": 37595}, {"id": 37655}, {"id": 37656}, {"id": 37657}, {"id": 37690}, {"id": 37691}, {"id": 37692}, {"id": 37693}, {"id": 37694}, {"id": 37695}, {"id": 37698}, {"id": 37699}, {"id": 37700}, {"id": 37702}, {"id": 37703}, {"id": 37755}, {"id": 37789}, {"id": 37790}, {"id": 37791}, {"id": 37792}, {"id": 37812}, {"id": 37813}, {"id": 37814}, {"id": 37816}, {"id": 37817}, {"id": 37818}, {"id": 37819}, {"id": 37820}, {"id": 37821}, {"id": 37823}, {"id": 37824}, {"id": 37825}, {"id": 37916}, {"id": 37917}, {"id": 37918}, {"id": 37919}, {"id": 37920}, {"id": 37921}, {"id": 37922}, {"id": 37934}, {"id": 37935}, {"id": 37936}, {"id": 37938}, {"id": 37939}, {"id": 37967}, {"id": 37968}, {"id": 37993}, {"id": 37994}, {"id": 37995}, {"id": 38009}, {"id": 38019}, {"id": 38066}, {"id": 38067}, {"id": 38068}, {"id": 38069}, {"id": 38081}, {"id": 38105}, {"id": 38106}, {"id": 38141}, {"id": 38142}, {"id": 38203}, {"id": 38223}, {"id": 38224}, {"id": 38225}, {"id": 38398}, {"id": 38399}, {"id": 38400}, {"id": 38401}, {"id": 38424}, {"id": 38425}, {"id": 38427}, {"id": 38428}, {"id": 38429}, {"id": 38430}, {"id": 38432}, {"id": 38433}, {"id": 38434}, {"id": 38435}, {"id": 38436}, {"id": 38437}, {"id": 38439}, {"id": 38440}, {"id": 38441}, {"id": 38468}, {"id": 38469}, {"id": 38470}, {"id": 38472}, {"id": 38473}, {"id": 38474}, {"id": 38538}, {"id": 38634}, {"id": 38653}, {"id": 38654}, {"id": 38659}, {"id": 38660}, {"id": 38714}, {"id": 38715}, {"id": 38772}, {"id": 38773}, {"id": 38828}, {"id": 38834}, {"id": 38835}, {"id": 38891}, {"id": 38892}, {"id": 38893}, {"id": 38907}, {"id": 38960}, {"id": 38961}, {"id": 39039}, {"id": 39132}, {"id": 39143}, {"id": 39144}, {"id": 39159}, {"id": 39160}, {"id": 39161}, {"id": 39182}, {"id": 39186}, {"id": 39187}, {"id": 39188}, {"id": 39192}, {"id": 39193}, {"id": 39411}, {"id": 39500}, {"id": 39544}, {"id": 39652}, {"id": 39653}, {"id": 39654}, {"id": 39655}, {"id": 39656}, {"id": 39657}, {"id": 39658}, {"id": 39660}, {"id": 39675}, {"id": 39676}, {"id": 39711}, {"id": 39712}, {"id": 39780}, {"id": 39802}, {"id": 39820}, {"id": 39829}, {"id": 39830}, {"id": 39831}, {"id": 39832}, {"id": 39833}, {"id": 40003}, {"id": 40004}, {"id": 40005}, {"id": 40015}, {"id": 40039}, {"id": 40097}, {"id": 40098}, {"id": 40099}, {"id": 40100}, {"id": 40112}, {"id": 40113}, {"id": 40114}, {"id": 40125}, {"id": 40126}, {"id": 40131}, {"id": 40132}, {"id": 40133}, {"id": 40134}, {"id": 40135}, {"id": 40136}, {"id": 40145}, {"id": 40146}, {"id": 40154}, {"id": 40155}, {"id": 40168}, {"id": 40192}, {"id": 40223}, {"id": 40224}, {"id": 40225}, {"id": 40226}, {"id": 40227}, {"id": 40229}, {"id": 40230}, {"id": 40231}, {"id": 40232}, {"id": 40233}, {"id": 40234}, {"id": 40235}, {"id": 40236}, {"id": 40237}, {"id": 40238}, {"id": 40255}, {"id": 40265}, {"id": 40266}, {"id": 40267}, {"id": 40501}, {"id": 43061}, {"id": 43726}, {"id": 43727}, {"id": 43728}, {"id": 47269}, {"id": 47339}, {"id": 48007}]', '[{"id": 42382}, {"id": 56363}, {"id": 55712}, {"id": 43734}, {"id": 44795}, {"id": 40617}, {"id": 55803}, {"id": 56081}, {"id": 57350}, {"id": 58342}, {"id": 56217}, {"id": 56090}, {"id": 56571}, {"id": 57349}, {"id": 58043}, {"id": 58703}, {"id": 58592}, {"id": 58719}, {"id": 56392}, {"id": 56229}, {"id": 46699}]', '716', '<p>Followed by <a href="https://comicvine.gamespot.com/batman/4050-42721/" data-ref-id="4050-42721">Batman Volume 2</a>.</p><p>The entire run of Batman still stands upon large controversies over who actually came up with some of the characters. <a href="/bob-kane/4040-19137/" data-ref-id="4040-19137">Bob Kane</a> supposedly came up with the idea for the hero, but it has been suggested that he only came up with a "Bird-man" and <a href="/bill-finger/4040-43591/" data-ref-id="4040-43591">Bill Finger</a> suggested he be a "Bat-man". Both creators, however, share credit for this character. As for the <a href="/joker/4005-1702/" data-ref-id="4005-1702">Joker</a>, the first concept sketch was drawn by <a href="/jerry-robinson/4040-9680/" data-ref-id="4040-9680">Jerry Robinson</a>, but Kane disputed that his input was "minimal" suggesting he and Bill came up with the idea. Kane also finagled many legal aspects of Batman related print and media ensuring he received sole credit. Prior to 2016, every movie and comic read "Batman created by Bob Kane", but following a campaign by the relatives of Bill Finger, all future credits have been changed to "Batman created by Bob Kane with Bill Finger". Robinson and Finger came up with the character, <a href="/dick-grayson/4005-1691/" data-ref-id="4005-1691">Robin</a> after "Robinhood". Bob Kane and Sheldon Moldoff co-created numerous bat-creations including <a href="/alfred/4005-5556/" data-ref-id="4005-5556">Alfred Pennyworth</a>, <a href="/poison-ivy/4005-1697/" data-ref-id="4005-1697">Poison Ivy,</a> <a href="/mr-freeze/4005-3715/" data-ref-id="4005-3715">Mr. Freeze</a>, <a href="/batwoman/4005-9052/" data-ref-id="4005-9052">Batwoman</a>, <a href="/batgirl/4050-7205/" data-ref-id="4050-7205">Batgirl</a> as well as <a href="/bat-mite/4005-23170/" data-ref-id="4005-23170">Bat-Mite</a> and <a href="/ace-the-bat-hound/4005-31302/" data-ref-id="4005-31302">Ace the Bat-Hound</a> just to name a few. <a href="/bill-finger/4040-43591/" data-ref-id="4040-43591">Bill Finger</a> also co-created <a href="/penguin/4005-4885/" data-ref-id="4005-4885">Penguin</a>, <a href="/riddler/4005-3718/" data-ref-id="4005-3718">Riddler</a>, and <a href="/catwoman/4005-1698/" data-ref-id="4005-1698">Catwoman</a>.</p><figure data-align="right" data-img-src="https://static.comicvine.com/uploads/original/6/64770/1681131-batman1ad.jpg" data-ref-id="1300-1681131" data-size="small" data-ratio="1.3854545454545" data-width="550" data-embed-type="image" style="width: 550px"><a class="fluid-height" style="padding-bottom:138.5%" href="https://static.comicvine.com/uploads/original/6/64770/1681131-batman1ad.jpg" data-ref-id="1300-1681131"><img alt="Ad for Batman #1" src="https://comicvine.gamespot.com/a/uploads/scale_small/6/64770/1681131-batman1ad.jpg" srcset="https://comicvine.gamespot.com/a/uploads/original/6/64770/1681131-batman1ad.jpg 550w, https://comicvine.gamespot.com/a/uploads/scale_medium/6/64770/1681131-batman1ad.jpg 480w, https://comicvine.gamespot.com/a/uploads/scale_small/6/64770/1681131-batman1ad.jpg 461w" sizes="(max-width: 461px) 100vw, 461px" data-width="461"></a><figcaption>Ad for Batman #1</figcaption></figure><p>One of DC''s longest running books showcasing the adventures of the Dark Knight, <a href="/batman/4005-1699/" data-ref-id="4005-1699">Batman</a>. Throughout the years, a majority of Batman''s marquee storylines have happened within the pages of this book including, but not limited to the death of the second Robin, <a href="/jason-todd/4005-6849/" data-ref-id="4005-6849">Jason Todd</a>, and <a href="/bane/4005-6129/" data-ref-id="4005-6129">Bane</a> breaking Batman''s back, leading to <a href="/jean-paul-valley/4005-12834/" data-ref-id="4005-12834">Jean-Paul Valley</a> to assume the role of Batman for a period of time in the 90s.</p><p>In 2006, superstar writer <a href="/grant-morrison/4040-40434/" data-ref-id="4040-40434">Grant Morrison</a> took over the book. Morrison wrote stories that introduced readers to Bruce''s son <a href="/damian-wayne/4005-42413/" data-ref-id="4005-42413">Damian Wayne</a> as well as putting Bruce through a series of near-fatal trials against <a href="/black-glove/4060-54825/" data-ref-id="4060-54825">The Black Glove</a> and <a href="/doctor-hurt/4005-54826/" data-ref-id="4005-54826">Doctor Hurt</a>, leading up to the epic 2008 storylines of <a href="/batman-rip/4045-55116/" data-ref-id="4045-55116">Batman RIP</a> and <a href="/final-crisis/4045-51642/" data-ref-id="4045-51642">Final Crisis</a> where Bruce Wayne had apparently died at the hands of the evil god <a href="/darkseid/4005-2349/" data-ref-id="4005-2349">Darkseid</a>.</p><p>After Bruce''s "death," and the <a href="/battle-for-the-cowl/4045-55808/" data-ref-id="4045-55808">Battle for the Cowl</a>, <a href="/dick-grayson/4005-1691/" data-ref-id="4005-1691">Dick Grayson</a>, the first Robin, took up the mantle of Batman, continuing to protect Gotham exactly as his mentor had. He even took in Damian as his own Robin. With the exception of two issues set prior to the events of <a href="/final-crisis/4045-51642/" data-ref-id="4045-51642">Final Crisis</a>, Dick Grayson has been the star of the book since issue #687.</p><p>When the superhero community learned that Bruce Wayne had never actually died, and was sent back in time by Darkseid, Dick Grayson eventually knew that his time as Batman would soon end. But with Bruce''s return, and formation of <a href="/batman-inc/4060-57839/" data-ref-id="4060-57839">Batman Incorporated</a>, Bruce deemed Dick Grayson the Batman of Gotham City, as he travelled the world, searching for more recruits for his new organization.</p><p><a href="/charles-paris/4040-38494/" data-ref-id="4040-38494">Charles Paris</a> has drawn the most issues of Batman thus far at 128. <a href="/dennis-oneil/4040-40861/" data-ref-id="4040-40861">Denny O''Neil</a> is a long time writer and editor at DC with 211 issues. He also contributed the location of <a href="/arkham-asylum/4020-31682/" data-ref-id="4020-31682">Arkham Asylum</a> as well as the characters <a href="/man-bat/4005-6131/" data-ref-id="4005-6131">Man-Bat</a>, <a href="/ras-al-ghul/4005-40816/" data-ref-id="4005-40816">Ra''s al Ghul</a> and <a href="/talia-al-ghul/4005-4917/" data-ref-id="4005-4917">Talia al Ghul</a>.</p><p>In September 2011, DC Comics relaunched their entire line in an event known as "<a href="/the-new-52/4015-56061/" data-ref-id="4015-56061">The New 52</a>" which would see the premiere of fifty-two new titles, thus the long-running Batman series ended with #713 during <a href="/tony-daniel/4040-4663/" data-ref-id="4040-4663">Tony S. Daniel</a>''s run on the title. In the new line, however, Tony Daniel will continue writing in the "Batman universe" but under the character''s other main title, <a href="/detective-comics/4050-18058/" data-ref-id="4050-18058">Detective Comics</a>. The new Batman series will be written instead by Scott Snyder (who was writing Detective Comics pre-relaunch).</p><h4>For Post <a href="/flashpoint/4045-56280/" data-ref-id="4045-56280">Flashpoint</a> volume 2, refer to <a href="/batman/4050-42721/" data-ref-id="4050-42721">Batman</a>.</h4><h4><b>Writers:</b></h4><p><b>Pre-Crisis</b></p><ul><li><a href="/bill-finger/4040-43591/" data-ref-id="4040-43591">Bill Finger</a> #1-13, 15, 18, 20, 22-23, 25, 28-36, 38-40, 42-45, 47-50, 52-53, 55-71, 74, 76-80, 82, 84-85, 87-90, 92-93, 95-105, 107-108, 110-116, 118-148, 150-160, 163, 167, 170, 176-177, 182, 185, 187, 193, 198, 200, 203, 208, 213, 218, 223, 228, 233, 236-237, 241-242, 254-259, 261</li><li><a href="/joseph-greene/4040-64596/" data-ref-id="4040-64596">Joseph Greene</a> #10, 17, 21, 26, 31, 261</li><li><a href="/jack-schiff/4040-46689/" data-ref-id="4040-46689">Jack Schiff</a> #10, 13, 15, 21, 26</li><li><a href="/edmond-hamilton/4040-42401/" data-ref-id="4040-42401">Edmond Hamilton</a> #11, 38, 76-78, 83, 85-86, 88, 91, 93-95, 98-99, 101, 104, 109-112, 182, 185, 187, 193, 198, 208, 218, 228, 238, 254, 261</li><li><a href="/don-cameron/4040-9802/" data-ref-id="4040-9802">Don Cameron</a> #12-17, 19-21, 23-32, 36, 38, 46, 213, 239, 256-261</li><li><a href="/ruth-lyons-kaufman/4040-76719/" data-ref-id="4040-76719">Ruth Lyon Kauffman</a> #16, 260</li><li><a href="/joe-samachson/4040-46798/" data-ref-id="4040-46798">Joseph Samachson</a> #18-19, 24, 27, 31</li><li><a href="/alvin-schwartz/4040-46732/" data-ref-id="4040-46732">Alvin Schwartz</a> #21-22, 25, 28, 36, 74, 83, 176, 187, 198, 255, 260</li><li><a href="/mort-weisinger/4040-42404/" data-ref-id="4040-42404">Mort Weisinger</a> #22, 257</li>