id": 21008}, {"id": 21031}, {"id": 21032}, {"id": 21096}, {"id": 21451}, {"id": 21452}, {"id": 21456}, {"id": 21460}, {"id": 21461}, {"id": 21464}, {"id": 21467}, {"id": 21982}, {"id": 22080}, {"id": 22207}, {"id": 22209}, {"id": 22211}, {"id": 22215}, {"id": 22225}, {"id": 22232}, {"id": 22240}, {"id": 22541}, {"id": 22650}, {"id": 22677}, {"id": 23356}, {"id": 23563}, {"id": 23833}, {"id": 23881}, {"id": 23890}, {"id": 23911}, {"id": 23983}, {"id": 24069}, {"id": 24088}, {"id": 24089}, {"id": 24150}, {"id": 24194}, {"id": 24509}, {"id": 24902}, {"id": 26557}, {"id": 30429}, {"id": 32813}, {"id": 33342}, {"id": 33661}, {"id": 33662}, {"id": 33672}, {"id": 33703}, {"id": 34064}, {"id": 35568}, {"id": 36674}, {"id": 37506}, {"id": 37708}, {"id": 38376}, {"id": 38510}, {"id": 38634}, {"id": 38758}, {"id": 38759}, {"id": 38760}, {"id": 38840}, {"id": 38912}, {"id": 39117}, {"id": 39448}, {"id": 39591}, {"id": 39976}, {"id": 40118}, {"id": 42864}, {"id": 44043}, {"id": 44064}, {"id": 48858}, {"id": 50396}, {"id": 50558}, {"id": 51987}, {"id": 53218}, {"id": 53680}, {"id": 54152}, {"id": 55602}, {"id": 55607}, {"id": 56004}, {"id": 56085}, {"id": 56982}, {"id": 57793}, {"id": 58003}, {"id": 58004}, {"id": 58011}, {"id": 60136}, {"id": 61930}, {"id": 62176}, {"id": 62540}, {"id": 62679}, {"id": 63025}, {"id": 63029}, {"id": 63030}, {"id": 63031}, {"id": 63208}, {"id": 63211}, {"id": 63212}, {"id": 63216}, {"id": 63217}, {"id": 63223}, {"id": 65433}, {"id": 65435}, {"id": 65437}, {"id": 65438}, {"id": 65440}, {"id": 65441}, {"id": 65442}, {"id": 65443}, {"id": 65444}, {"id": 65448}, {"id": 65449}, {"id": 65450}, {"id": 65451}, {"id": 65452}, {"id": 65453}, {"id": 65454}, {"id": 65456}, {"id": 65457}, {"id": 65458}, {"id": 67377}, {"id": 67748}, {"id": 68142}, {"id": 68887}, {"id": 68888}, {"id": 68891}, {"id": 69778}, {"id": 70037}, {"id": 70041}, {"id": 70372}, {"id": 70727}, {"id": 71367}, {"id": 72174}, {"id": 74611}, {"id": 74823}, {"id": 74829}, {"id": 74830}, {"id": 74831}, {"id": 74832}, {"id": 74833}, {"id": 74850}, {"id": 74854}, {"id": 74880}, {"id": 74901}, {"id": 74924}, {"id": 74938}, {"id": 74949}, {"id": 75492}, {"id": 76710}, {"id": 77162}, {"id": 78908}, {"id": 80104}, {"id": 82086}, {"id": 82102}, {"id": 84181}, {"id": 89037}, {"id": 89354}, {"id": 89969}, {"id": 89970}, {"id": 89971}, {"id": 89972}, {"id": 89973}, {"id": 89974}, {"id": 90042}, {"id": 90096}, {"id": 90116}, {"id": 90121}, {"id": 90354}, {"id": 90416}, {"id": 91795}, {"id": 96170}, {"id": 98371}, {"id": 98526}, {"id": 101564}, {"id": 103382}, {"id": 103383}, {"id": 103424}, {"id": 107735}, {"id": 112160}, {"id": 112161}, {"id": 112406}, {"id": 112740}, {"id": 112824}, {"id": 112825}, {"id": 112826}, {"id": 112827}, {"id": 112828}, {"id": 112829}, {"id": 112830}, {"id": 113511}, {"id": 113512}, {"id": 114175}, {"id": 114176}, {"id": 115650}, {"id": 121017}, {"id": 122657}, {"id": 124498}, {"id": 124499}, {"id": 124500}, {"id": 124502}, {"id": 124503}, {"id": 124822}, {"id": 126919}, {"id": 128169}, {"id": 128272}, {"id": 137548}, {"id": 137557}, {"id": 137574}, {"id": 138204}, {"id": 138205}, {"id": 138206}, {"id": 141055}, {"id": 143188}, {"id": 143189}, {"id": 143199}, {"id": 143202}, {"id": 143213}, {"id": 143214}, {"id": 143251}, {"id": 143252}, {"id": 143261}, {"id": 144795}, {"id": 148008}, {"id": 148009}, {"id": 148010}, {"id": 152566}, {"id": 153399}, {"id": 157479}, {"id": 158305}, {"id": 158306}, {"id": 158307}, {"id": 158308}, {"id": 177929}, {"id": 187342}, {"id": 187533}, {"id": 187534}, {"id": 187535}, {"id": 187582}, {"id": 188272}, {"id": 188273}, {"id": 188390}, {"id": 188458}, {"id": 189299}, {"id": 189855}, {"id": 189857}, {"id": 192295}, {"id": 192298}, {"id": 192299}, {"id": 192302}, {"id": 192303}, {"id": 192309}, {"id": 192310}, {"id": 192312}, {"id": 192313}, {"id": 192314}, {"id": 192328}, {"id": 195302}]', '[{"id": 56090}, {"id": 55712}, {"id": 44795}]', '170', '<p>In  1941, Albert E. Kanter introduced <a data-ref-id="4050-22552" href="/classic-comics/4050-22552/" slug="classic-comics"> Classic Comics</a>, later renamed  Classics Illustrated. Kanter’s idea was to use the comic form to make  great literature accessible to readers who might never otherwise make  the effort. Whether his idea represented a watering down of the  classics, as some critics claimed, it was an amazingly popular move.  Each of the 169 comics in this series were reprinted numerous times,  with 23rd printings being relatively common. Their popularity even  extended to schools, where the colorful, well-written adaptations must  have seemed a welcome alternative to reading lengthy texts.<br/><br/>Kanter  later introduced <a data-ref-id="4050-28659" href="/classics-illustrated-junior/4050-28659/" slug="classics-illustrated-junior">   Classics Illustrated Junior</a>, adapting children’s  literature for younger readers. The series also gave rise to numerous  imitations over the years.</p>', '914', 'Classics Illustrated', '1941', '124408', 'https://comicvine.gamespot.com/a/uploads/screen_medium/0/77/321316-914-124408-1-classics-illustrated.jpg', '57');
INSERT INTO volumes (characters, concepts, count_of_issues, description, id, name, start_year, first_issue.id, image.screen_url, publisher.id) VALUES ('[{"id": 73230}, {"id": 9605}, {"id": 18136}, {"id": 73232}, {"id": 73231}, {"id": 115961}, {"id": 18141}, {"id": 16890}, {"id": 177932}, {"id": 38858}, {"id": 160345}, {"id": 141930}, {"id": 18144}, {"id": 32525}, {"id": 9671}, {"id": 73253}, {"id": 90520}, {"id": 142684}, {"id": 34422}, {"id": 69764}, {"id": 69762}, {"id": 69761}, {"id": 69760}, {"id": 47403}, {"id": 4070}, {"id": 18142}, {"id": 14335}, {"id": 11766}, {"id": 11432}, {"id": 11119}, {"id": 10397}, {"id": 9299}, {"id": 4537}]', '[{"id": 44795}]', '36', '<p>Boy Commandos was a Golden Age anthology title published by DC Comics in the 1940''s, each issue containing a few stories of the titular group as well as the occasional filler or short story. Created by Jack Kirby and Joe Simon, Boy Commandos became the third best-selling title at DC with over a million copies a month. Originally the book featured the boys and their adult leader, Rip Carter fighting in World War II but following the end of the war the series continued but no longer as a war comic. Near the end of its run the line-up of the team began to change and finally the series ended in 1949 after a run of thirty-six issues.</p><h4>Collected Editions</h4><ul><li><a href="/boy-commandos-by-joe-simon-and-jack-kirby-1-volume/4000-302186/" data-ref-id="4000-302186">Boy Commandos by Joe Simon and Jack Kirby Volume One</a> (#1-2)</li><li><a href="https://comicvine.gamespot.com/dc-goes-to-war/4050-127614/">DC Goes To War</a> (#1)</li><li><a href="/boy-commandos-by-joe-simon-and-jack-kirby-2-volume/4000-507146/" data-ref-id="4000-507146">Boy Commandos by Joe Simon and Jack Kirby Volume Two</a> (#3-5)</li></ul>', '921', 'Boy Commandos', '1942', '52350', 'https://comicvine.gamespot.com/a/uploads/screen_medium/0/4/45206-921-52350-1-boy-commandos.jpg', '10');
INSERT INTO volumes (characters, concepts, count_of_issues, description, id, name, start_year, first_issue.id, image.screen_url, publisher.id) VALUES ('[{"id": 9820}, {"id": 36734}, {"id": 27813}, {"id": 34444}, {"id": 44312}, {"id": 35144}, {"id": 44301}, {"id": 44056}, {"id": 44027}, {"id": 40182}, {"id": 38778}, {"id": 44303}, {"id": 34058}, {"id": 30498}, {"id": 30467}, {"id": 30413}, {"id": 30412}, {"id": 44302}, {"id": 30410}, {"id": 44306}, {"id": 44307}, {"id": 44308}, {"id": 44309}, {"id": 44313}, {"id": 44340}, {"id": 48708}, {"id": 52544}, {"id": 67099}, {"id": 97710}, {"id": 97711}, {"id": 97712}, {"id": 14323}, {"id": 5890}, {"id": 7289}, {"id": 7302}, {"id": 9807}, {"id": 9810}, {"id": 9812}, {"id": 9814}, {"id": 9815}, {"id": 9816}, {"id": 9817}, {"id": 9818}, {"id": 9819}, {"id": 10790}, {"id": 30411}, {"id": 14349}, {"id": 14350}, {"id": 14391}, {"id": 16047}, {"id": 20562}, {"id": 21072}, {"id": 21893}, {"id": 23445}, {"id": 23457}, {"id": 26836}, {"id": 27380}, {"id": 30409}, {"id": 3951}]', 'NaN', '4', '<p>Picture Stories from the Bible (Old Testament) was a Golden Age anthology comic released by DC Comics in the early 40''s that ran for four issues featuring such Biblical characters as Moses, Joseph and Saul but due to it being copyrighted and published by M.C. Gaines it would later be reprinted under his publisher EC Comics. It also had a counterpart featuring comic retellings of stories from the <a data-ref-id="4050-988" href="/picture-stories-from-the-bible-new-testament/4050-988/" slug="picture-stories-from-the-bible-new-testament">New Testament</a>.</p>', '923', 'Picture Stories from the Bible (Old Testament)', '1942', '90142', 'https://comicvine.gamespot.com/a/uploads/screen_medium/0/9116/1955652-1.jpg', '10');
